class CityFlagStaticDataTester {
public:
    static CityFlagStaticDataKey make_key (u16 raw) {
        return CityFlagStaticDataKey::from_raw(raw);
    }
};

void test_set_items_updates_count () {
    static CityFlagStaticDataStruct items[3];
    items[0].effects.items[0].type = 1;  items[0].effects.items[1].type = 10;
    items[1].effects.items[0].type = 2;  items[1].effects.items[1].type = 20;
    items[2].effects.items[0].type = 3;  items[2].effects.items[1].type = 30;
    CityFlagStaticData data;
    data.set_items(items, 3);
    note_result(data.get_item_count() == 3, "set_items updates item count");
    summarize_test_results();
}

void test_get_item_returns_expected_struct_by_key () {
    static CityFlagStaticDataStruct items[4];
    items[0].effects.items[0].type = 7;   items[0].effects.items[1].type = 70;
    items[1].effects.items[0].type = 8;   items[1].effects.items[1].type = 80;
    items[2].effects.items[0].type = 9;   items[2].effects.items[1].type = 90;
    items[3].effects.items[0].type = 10;  items[3].effects.items[1].type = 100;
    CityFlagStaticData data;
    data.set_items(items, 4);

    CityFlagStaticDataKey key = CityFlagStaticDataTester::make_key(2);
    const CityFlagStaticDataStruct& item = data.get_item(key);

    note_result(item.effects.items[0].type == 9, "get_item returns expected member1");
    note_result(item.effects.items[1].type == 90, "get_item returns expected member2");
    summarize_test_results();
}

void test_get_item_returns_reference_to_backing_array () {
    static CityFlagStaticDataStruct items[2];
    items[0].effects.items[0].type = 11;  items[0].effects.items[1].type = 110;
    items[1].effects.items[0].type = 12;  items[1].effects.items[1].type = 120;
    CityFlagStaticData data;
    data.set_items(items, 2);

    CityFlagStaticDataKey key = CityFlagStaticDataTester::make_key(1);
    const CityFlagStaticDataStruct& item = data.get_item(key);

    note_result(&item == &items[1], "get_item returns reference into backing array");
    summarize_test_results();
}

void test_set_items_can_replace_array_and_count () {
    static CityFlagStaticDataStruct items_a[2];
    items_a[0].effects.items[0].type = 21; items_a[0].effects.items[1].type = 210;
    items_a[1].effects.items[0].type = 22; items_a[1].effects.items[1].type = 220;
    static CityFlagStaticDataStruct items_b[5];
    items_b[0].effects.items[0].type = 31; items_b[0].effects.items[1].type = 131;
    items_b[1].effects.items[0].type = 32; items_b[1].effects.items[1].type = 132;
    items_b[2].effects.items[0].type = 33; items_b[2].effects.items[1].type = 133;
    items_b[3].effects.items[0].type = 34; items_b[3].effects.items[1].type = 134;
    items_b[4].effects.items[0].type = 35; items_b[4].effects.items[1].type = 135;

    CityFlagStaticData data;
    data.set_items(items_a, 2);
    note_result(data.get_item_count() == 2, "initial array count set");

    data.set_items(items_b, 5);
    note_result(data.get_item_count() == 5, "replacement array count set");
    CityFlagStaticDataKey key = CityFlagStaticDataTester::make_key(4);
    const CityFlagStaticDataStruct& item = data.get_item(key);
    note_result(item.effects.items[0].type == 35, "replacement array item accessible");
    summarize_test_results();
}

void test_zero_count_is_allowed () {
    static CityFlagStaticDataStruct items[1];
    items[0].effects.items[0].type = 41; items[0].effects.items[1].type = 141;
    CityFlagStaticData data;
    data.set_items(items, 0);
    note_result(data.get_item_count() == 0, "zero item count can be stored");
    summarize_test_results();
}

void test_take_ownership_copies_backing_array () {
    CityFlagStaticDataStruct* items = new CityFlagStaticDataStruct[2];
    items[0].effects.items[0].type = 51; items[0].effects.items[1].type = 151;
    items[1].effects.items[0].type = 52; items[1].effects.items[1].type = 152;
    CityFlagStaticData data;
    data.set_items(items, 2);
    CityFlagStaticDataKey key = CityFlagStaticDataTester::make_key(1);
    const void* src_ref = &data.get_item(key);
    data.take_ownership();
    const CityFlagStaticDataStruct& item = data.get_item(key);

    note_result(&item != src_ref, "take_ownership uses a distinct buffer");
    note_result(item.effects.items[0].type == 52, "take_ownership preserves member1");
    note_result(item.effects.items[1].type == 152, "take_ownership preserves member2");
    data.release_items();
    summarize_test_results();
}

